import React, { useEffect, useState } from "react";
import axios from "axios";
import { BookingRecord } from "../types";

const API_BASE = "http://localhost:5000/api";

const Bookings: React.FC = () => {
  const [bookings, setBookings] = useState<BookingRecord[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBookings = async () => {
      try {
        const response = await axios.get<BookingRecord[]>(`${API_BASE}/bookings`);
        setBookings(response.data);
      } catch (error) {
        console.error("Failed to fetch bookings", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBookings();
  }, []);

  return (
    <section>
      <h2 className="mb-5 text-2xl font-bold text-slate-900">All Bookings</h2>

      {loading ? <p className="text-slate-600">Loading bookings...</p> : null}
      {!loading && bookings.length === 0 ? (
        <div className="rounded-xl bg-white p-6 text-center text-slate-600 shadow-travel ring-1 ring-slate-200">
          No bookings found yet.
        </div>
      ) : null}

      <div className="grid gap-4">
        {bookings.map((booking) => (
          <article key={booking.id} className="rounded-2xl bg-white p-5 shadow-travel ring-1 ring-slate-200">
            <div className="flex flex-wrap items-start justify-between gap-3">
              <div>
                <h3 className="text-lg font-bold text-slate-900">{booking.busName}</h3>
                <p className="text-sm text-slate-600">{booking.route}</p>
                <p className="mt-1 text-xs text-slate-500">Booking ID: {booking.id}</p>
              </div>
              <p className="rounded-full bg-emerald-100 px-3 py-1 text-xs font-semibold text-emerald-700">
                {booking.paymentMethod}
              </p>
            </div>

            <div className="mt-4 grid gap-2 text-sm text-slate-700 md:grid-cols-2">
              <p>
                <span className="font-medium">Seats:</span> {booking.selectedSeats.join(", ")}
              </p>
              <p>
                <span className="font-medium">Passengers:</span> {booking.passengerDetails.map((p) => p.name).join(", ")}
              </p>
              <p>
                <span className="font-medium">Total:</span> INR {booking.totalPrice}
              </p>
              <p>
                <span className="font-medium">Booked At:</span> {new Date(booking.bookedAt).toLocaleString()}
              </p>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
};

export default Bookings;
